// Core requirements logic. Pure functions over an array of requirements.
// A requirement is: { id: number, title: string, done: boolean }

/**
 * Return the list of requirements. Returns a shallow copy so callers
 * cannot mutate the source array by accident.
 * @param {Array} requirements
 * @returns {Array}
 */
export function listRequirements(requirements) {
  return [...requirements];
}

/**
 * Add a new requirement with the given title. Returns a new array.
 * The new id is one greater than the current maximum id (or 1 if empty).
 * @param {Array} requirements
 * @param {string} title
 * @returns {Array}
 */
export function addRequirement(requirements, title) {
  const trimmed = typeof title === "string" ? title.trim() : "";
  if (!trimmed) {
    throw new Error("A requirement title is required.");
  }
  const nextId = requirements.reduce((max, r) => Math.max(max, r.id), 0) + 1;
  return [...requirements, { id: nextId, title: trimmed, done: false }];
}

/**
 * Toggle the done state of the requirement with the given id.
 * Returns a new array. Throws if the id is not found.
 * @param {Array} requirements
 * @param {number} id
 * @returns {Array}
 */
export function toggleRequirement(requirements, id) {
  let found = false;
  const next = requirements.map((r) => {
    if (r.id === id) {
      found = true;
      return { ...r, done: !r.done };
    }
    return r;
  });
  if (!found) {
    throw new Error(`No requirement found with id ${id}.`);
  }
  return next;
}

