#!/usr/bin/env node
// CLI for the requirements tracker.
// Usage:
//   reqs list
//   reqs add <title>
//   reqs toggle <id>

import { readFile, writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import {
  listRequirements,
  addRequirement,
  toggleRequirement,
} from "../src/requirements.js";

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_FILE = join(__dirname, "..", "requirements.json");

async function load() {
  const raw = await readFile(DATA_FILE, "utf8");
  return JSON.parse(raw);
}

async function save(requirements) {
  await writeFile(DATA_FILE, JSON.stringify(requirements, null, 2) + "\n");
}

function printList(requirements) {
  if (requirements.length === 0) {
    console.log("No requirements yet. Add one with: reqs add <title>");
    return;
  }
  for (const r of requirements) {
    const mark = r.done ? "[x]" : "[ ]";
    console.log(`${mark} #${r.id} ${r.title}`);
  }
}

async function main() {
  const [command, ...args] = process.argv.slice(2);

  switch (command) {
    case "list":
    case undefined: {
      const requirements = await load();
      printList(listRequirements(requirements));
      break;
    }
    case "add": {
      const title = args.join(" ");
      const requirements = await load();
      const next = addRequirement(requirements, title);
      await save(next);
      const added = next[next.length - 1];
      console.log(`Added #${added.id} ${added.title}`);
      break;
    }
    case "toggle": {
      const id = Number(args[0]);
      if (!Number.isInteger(id)) {
        throw new Error("toggle requires a numeric id, e.g. reqs toggle 1");
      }
      const requirements = await load();
      const next = toggleRequirement(requirements, id);
      await save(next);
      const updated = next.find((r) => r.id === id);
      const state = updated.done ? "done" : "open";
      console.log(`Toggled #${id} -> ${state}`);
      break;
    }
    default: {
      console.error(`Unknown command: ${command}`);
      console.error("Usage: reqs <list|add <title>|toggle <id>>");
      process.exitCode = 1;
    }
  }
}

main().catch((err) => {
  console.error(err.message);
  process.exitCode = 1;
});

