import { test } from "node:test";
import assert from "node:assert/strict";
import {
  listRequirements,
  addRequirement,
  toggleRequirement,
} from "../src/requirements.js";

const sample = () => [
  { id: 1, title: "First", done: false },
  { id: 2, title: "Second", done: true },
];

test("listRequirements returns all items", () => {
  const reqs = sample();
  assert.deepEqual(listRequirements(reqs), reqs);
});

test("listRequirements returns a copy, not the original array", () => {
  const reqs = sample();
  const result = listRequirements(reqs);
  assert.notEqual(result, reqs);
});

test("addRequirement appends a new open requirement", () => {
  const reqs = sample();
  const next = addRequirement(reqs, "Third");
  assert.equal(next.length, 3);
  assert.deepEqual(next[2], { id: 3, title: "Third", done: false });
});

test("addRequirement assigns id = max + 1", () => {
  const reqs = [{ id: 5, title: "Five", done: false }];
  const next = addRequirement(reqs, "New");
  assert.equal(next[1].id, 6);
});

test("addRequirement starts ids at 1 when empty", () => {
  const next = addRequirement([], "First");
  assert.equal(next[0].id, 1);
});

test("addRequirement does not mutate the original array", () => {
  const reqs = sample();
  addRequirement(reqs, "Third");
  assert.equal(reqs.length, 2);
});

test("addRequirement trims the title", () => {
  const next = addRequirement([], "  spaced  ");
  assert.equal(next[0].title, "spaced");
});

test("addRequirement throws on empty title", () => {
  assert.throws(() => addRequirement([], "   "), /title is required/);
});

test("toggleRequirement flips done state", () => {
  const reqs = sample();
  const next = toggleRequirement(reqs, 1);
  assert.equal(next[0].done, true);
  const back = toggleRequirement(next, 1);
  assert.equal(back[0].done, false);
});

test("toggleRequirement does not mutate the original array", () => {
  const reqs = sample();
  toggleRequirement(reqs, 1);
  assert.equal(reqs[0].done, false);
});

test("toggleRequirement throws on unknown id", () => {
  assert.throws(() => toggleRequirement(sample(), 99), /No requirement found/);
});

